#include <stdio.h>
#include <string.h> // For strlen
#include <ctype.h>  // For tolower

int main() {
    char str[101]; // Max 100 chars + null terminator
    int vowel_count = 0;
    int i;

    // Read a line of text
    // Using fgets to safely read a line up to 100 characters
    if (fgets(str, sizeof(str), stdin) == NULL) {
        return 1; // Error reading input
    }

    // Remove trailing newline character if present
    str[strcspn(str, "\n")] = 0;

    for (i = 0; str[i] != '\0'; i++) {
        // Convert character to lowercase for case-insensitive check
        char c = tolower(str[i]);

        // Check if the character is a vowel
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            vowel_count++;
        }
    }

    printf("%d\n", vowel_count);

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    int arr[100]; // Array to store up to 100 integers
    int i;

    // Read N
    if (scanf("%d", &N) != 1 || N < 1 || N > 100) {
        fprintf(stderr, "Invalid N. N must be between 1 and 100.\n");
        return 1;
    }

    // Read N integers into the array
    for (i = 0; i < N; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            fprintf(stderr, "Error reading array element.\n");
            return 1;
        }
    }

    // Initialize max_val and max_idx with the first element
    int max_val = arr[0];
    int max_idx = 0;

    // Iterate through the rest of the array to find the maximum value and its first index
    for (i = 1; i < N; i++) {
        if (arr[i] > max_val) {
            max_val = arr[i];
            max_idx = i; // Update index to the first occurrence
        }
    }

    printf("%d %d\n", max_val, max_idx);

    return 0;
}

#include <stdio.h>
#include <string.h> // For strlen, strcspn
#include <ctype.h>  // For isalpha, islower, isupper

int main() {
    char str[101]; // Max 100 chars + null terminator
    int shift;
    int i;

    // Read the string
    if (fgets(str, sizeof(str), stdin) == NULL) {
        return 1; // Error reading input
    }
    // Remove trailing newline character if present
    str[strcspn(str, "\n")] = 0;

    // Read the shift value
    if (scanf("%d", &shift) != 1 || shift < 0 || shift > 25) {
        fprintf(stderr, "Invalid shift value. Must be between 0 and 25.\n");
        return 1;
    }

    for (i = 0; str[i] != '\0'; i++) {
        char current_char = str[i];

        if (isalpha(current_char)) {
            if (islower(current_char)) {
                // Apply shift for lowercase letters
                current_char = 'a' + (current_char - 'a' + shift) % 26;
            } else if (isupper(current_char)) {
                // Apply shift for uppercase letters
                current_char = 'A' + (current_char - 'A' + shift) % 26;
            }
        }
        // Non-alphabetic characters are left unchanged
        str[i] = current_char;
    }

    printf("%s\n", str);

    return 0;
}
